export function SwapAssetSelector({
  title,
  swapBalance,
  staticOptions,
  onSelect,
  onBack,
  isMulti,
  selectedTokens = [],
  onToggle,
  onDone,
}: SwapAssetSelectorProps) {
  const [query, setQuery] = useState("");

  const allTokens = useMemo<SwapTokenOption[]>(() => {
    if (staticOptions) return staticOptions;
    if (!swapBalance) return [];
    return deriveTokenOptions(swapBalance);
  }, [swapBalance, staticOptions]);

  const filtered = useMemo(() => {
    if (!query.trim()) return allTokens;
    const q = query.toLowerCase();
    return allTokens.filter(
      (t) =>
        t.symbol.toLowerCase().includes(q) ||
        t.name.toLowerCase().includes(q) ||
        (t.chainName ?? "").toLowerCase().includes(q),
    );
  }, [allTokens, query]);

  const groupedFiltered = useMemo(() => {
    const groups: Record<string, SwapTokenOption[]> = {};
    for (const token of filtered) {
      if (!groups[token.symbol]) groups[token.symbol] = [];
      groups[token.symbol].push(token);
    }

    return Object.values(groups).map((group) => {
      let totalFiatVal = 0;
      let totalBalVal = 0;

      for (const t of group) {
        totalFiatVal += Number(t.balanceInFiat.replace(/[^0-9.]/g, "") || 0);
        totalBalVal += Number(t.balance.replace(/[^0-9.]/g, "") || 0);
      }

      return {
        symbol: group[0].symbol,
        logo: group[0].logo,
        totalFiat: `$${totalFiatVal.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 2 })}`,
        totalBal: `${totalBalVal.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 4 })} ${group[0].symbol}`,
        tokens: group,
      };
    }).sort((a, b) => {
      const aFiat = Number(a.totalFiat.replace(/[^0-9.]/g, "") || 0);
      const bFiat = Number(b.totalFiat.replace(/[^0-9.]/g, "") || 0);
      return bFiat - aFiat;
    });
  }, [filtered]);

  const [expandedGroups, setExpandedGroups] = useState<Set<string>>(new Set());

  const toggleGroup = (symbol: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setExpandedGroups((prev) => {
      const next = new Set(prev);
      if (next.has(symbol)) next.delete(symbol);
      else next.add(symbol);
      return next;
    });
  };

  const toggleGroupSelection = (groupTokens: SwapTokenOption[], isFullySelected: boolean, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isMulti || !onToggle) return;

    if (isFullySelected) {
      // Deselect all
      groupTokens.forEach(t => {
        if (selectedTokens.some(st => st.contractAddress === t.contractAddress && st.chainId === t.chainId)) {
          onToggle(t);
        }
      });
    } else {
      // Select all
      groupTokens.forEach(t => {
        if (!selectedTokens.some(st => st.contractAddress === t.contractAddress && st.chainId === t.chainId)) {
          onToggle(t);
        }
      });
    }
  };

  const renderTokenRow = (token: SwapTokenOption) => {
    const isSelected = selectedTokens.some(
      (st) =>
        st.contractAddress === token.contractAddress &&
        st.chainId === token.chainId
    );
    return (
      <button
        key={`${token.contractAddress}-${token.chainId}`}
        onClick={() => {
          if (isMulti && onToggle) {
            onToggle(token);
          } else if (!isMulti) {
            onSelect(token);
          }
        }}
        className="w-full flex items-center justify-between px-3 py-2.5 rounded-xl hover:bg-black/5 transition-colors group"
      >
        <div className="flex items-center gap-x-3">
          {isMulti && <CheckboxBox selected={isSelected} />}
           <div className="relative shrink-0">
            {token.logo ? (
              <img
                src={token.logo}
                alt={token.symbol}
                className="w-9 h-9 rounded-full border border-white shadow-sm object-cover"
                onError={(e) => {
                  (e.target as HTMLImageElement).style.display = "none";
                }}
              />
            ) : (
              <div
                className="w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold text-white"
                style={{
                  background:
                    "var(--interactive-button-primary-background, var(--foreground-brand, #006BF4))",
                }}
              >
                {token.symbol.slice(0, 2)}
              </div>
            )}
          </div>
          <div className="flex flex-col items-start">
            <span
              style={{
                fontFamily: "var(--font-geist-sans), sans-serif",
                fontWeight: 500,
                fontSize: "14px",
                color: "var(--foreground-primary, #161615)",
              }}
            >
              {token.symbol}
            </span>
            {token.chainName && (
              <span
                style={{
                  fontFamily: "var(--font-geist-sans), sans-serif",
                  fontSize: "12px",
                  color: "var(--foreground-muted, var(--foreground-muted, #848483))",
                }}
              >
                {token.chainName}
              </span>
            )}
          </div>
        </div>
        <div className="flex items-center gap-x-3">
          <div className="flex flex-col items-end">
            <span
              style={{
                fontFamily: "var(--font-geist-sans), sans-serif",
                fontWeight: 500,
                fontSize: "13px",
                color: "var(--foreground-primary, #161615)",
              }}
            >
              {token.balanceInFiat}
            </span>
            <span
              style={{
                fontFamily: "var(--font-geist-sans), sans-serif",
                fontSize: "12px",
                color: "var(--foreground-muted, var(--foreground-muted, #848483))",
              }}
            >
              {token.balance}
            </span>
          </div>
          <div className="w-5 h-5 shrink-0" />
        </div>
      </button>
    );
  };

  const isLoading = !staticOptions && swapBalance === null;

  return (
    <div className="flex flex-col h-full w-full antialiased">
      {/* Search */}
      <div className="pb-3">
        <div
          className="flex items-center"
          style={{
            height: "44px",
            gap: "8px",
            borderRadius: "12px",
            borderWidth: "1px",
            borderStyle: "solid",
            borderColor: "var(--border-default, var(--border-default, #E8E8E7))",
            paddingTop: "12px",
            paddingRight: "16px",
            paddingBottom: "12px",
            paddingLeft: "16px",
            background: "var(--background-tertiary, var(--background-tertiary, #F0F0EF))",
          }}
        >
          <Search
            style={{
              width: "20px",
              height: "20px",
              color: "var(--foreground-muted, var(--foreground-muted, #848483))",
            }}
            className="shrink-0"
          />
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search..."
            className="flex-1 bg-transparent border-none outline-none placeholder:text-[var(--foreground-muted, #848483)]"
            style={{
              fontFamily: "Geist, var(--font-geist-sans), sans-serif",
              fontWeight: 400,
              fontSize: "14px",
              lineHeight: "18px",
              color: "var(--widget-card-foreground-primary, var(--foreground-primary, #161615))",
            }}
          />
          {query && (
            <button onClick={() => setQuery("")} className="shrink-0">
              <X className="w-4 h-4 text-[var(--foreground-muted, #848483)]" />
            </button>
          )}
        </div>
      </div>

      {/* Token list */}
      <div className="flex-1 overflow-y-auto pb-4">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center py-10 gap-y-3">
            <Loader2 className="w-5 h-5 animate-spin text-gray-400" />
            <p className="text-sm text-gray-400">Loading assets…</p>
          </div>
        ) : filtered.length === 0 ? (
          <p className="text-sm text-center text-gray-400 py-8">
            No tokens found
          </p>
        ) : (
          <div
            style={{
              border: "1px solid var(--widget-card-border, var(--border-default, #E8E8E7))",
              maxHeight: "288px",
              borderRadius: "8px",
              borderWidth: "1px",
              overflowY: "auto",
              background: "var(--widget-card-background-primary, var(--background-secondary, #FFFFFE))",
            }}
            className="flex flex-col p-1 space-y-1"
          >
            {groupedFiltered.map((group) => {
              if (group.tokens.length === 1) {
                return renderTokenRow(group.tokens[0]);
              }

              const isExpanded = expandedGroups.has(group.symbol);
              const selectedCount = group.tokens.filter(t => 
                selectedTokens.some(st => st.contractAddress === t.contractAddress && st.chainId === t.chainId)
              ).length;
              const isFullySelected = selectedCount === group.tokens.length;
              const hasSelection = selectedCount > 0;

              return (
                <div key={group.symbol} className="flex flex-col w-full">
                  <button
                    onClick={(e) => toggleGroup(group.symbol, e)}
                    className="w-full flex items-center justify-between px-3 py-2.5 rounded-xl hover:bg-black/5 transition-colors group"
                  >
                    <div className="flex items-center gap-x-3">
                      {isMulti && (
                        <div onClick={(e) => toggleGroupSelection(group.tokens, isFullySelected, e)}>
                          <CheckboxBox selected={hasSelection} />
                        </div>
                      )}
                      <div className="relative shrink-0">
                        {group.logo ? (
                          <img
                            src={group.logo}
                            alt={group.symbol}
                            className="w-9 h-9 rounded-full border border-white shadow-sm object-cover"
                            onError={(e) => {
                              (e.target as HTMLImageElement).style.display = "none";
                            }}
                          />
                        ) : (
                          <div
                            className="w-9 h-9 rounded-full flex items-center justify-center text-xs font-bold text-white"
                            style={{
                              background:
                                "var(--interactive-button-primary-background, var(--foreground-brand, #006BF4))",
                            }}
                          >
                            {group.symbol.slice(0, 2)}
                          </div>
                        )}
                      </div>
                      <div className="flex flex-col items-start">
                        <span
                          style={{
                            fontFamily: "var(--font-geist-sans), sans-serif",
                            fontWeight: 500,
                            fontSize: "14px",
                            color: "var(--foreground-primary, #161615)",
                          }}
                        >
                          {group.symbol}
                        </span>
                        <span
                          style={{
                            fontFamily: "var(--font-geist-sans), sans-serif",
                            fontSize: "12px",
                            color: "var(--foreground-muted, var(--foreground-muted, #848483))",
                          }}
                        >
                          {group.tokens.length} Chains
                        </span>
                      </div>
                    </div>

                    <div className="flex items-center gap-x-3">
                      <div className="flex flex-col items-end">
                        <span
                          style={{
                            fontFamily: "var(--font-geist-sans), sans-serif",
                            fontWeight: 500,
                            fontSize: "13px",
                            color: "var(--foreground-primary, #161615)",
                          }}
                        >
                          {group.totalFiat}
                        </span>
                        <span
                          style={{
                            fontFamily: "var(--font-geist-sans), sans-serif",
                            fontSize: "12px",
                            color: "var(--foreground-muted, var(--foreground-muted, #848483))",
                          }}
                        >
                          {group.totalBal}
                        </span>
                      </div>
                      <div className="text-gray-400 shrink-0">
                        {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                      </div>
                    </div>
                  </button>

                  <div
                    className={`grid transition-all duration-300 ease-in-out ${
                      isExpanded ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0"
                    }`}
                  >
                    <div className="overflow-hidden">
                      <div className="flex flex-col pl-6 mt-1 space-y-1 py-1">
                        {group.tokens.map((token) => renderTokenRow(token))}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {isMulti && (
        <div className="pb-4 mt-auto">
          <button
            onClick={onDone}
            disabled={selectedTokens.length === 0}
            className="w-full font-medium text-white transition-opacity hover:opacity-90 disabled:opacity-50 active:opacity-100 flex items-center justify-center cursor-pointer"
            style={{
              background: "var(--foreground-brand, #006BF4)",
              boxShadow: "0px 1px 4px 0px #5555550D",
              height: "48px",
              borderRadius: "12px",
              fontSize: "14px",
            }}
          >
            Done
          </button>
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect } from "react";
import { type SwapTokenOption } from "./swap-asset-selector";

interface SwapIdleFormProps {
  amount: string;
  onAmountChange: (val: string, panel: "send" | "receive") => void;
  fromTokens: SwapTokenOption[];
  toToken?: SwapTokenOption;
  totalBalance: string;
  receiveBalance?: string;
  usdValue: string;
  onOpenSourcePicker: () => void;
  onOpenDestPicker: () => void;
  onOpenRecipientPicker?: () => void;
  recipientAddress?: string;
  swapType: "exactIn" | "exactOut";
}

/** Chevron down icon used in asset selector pills */
const ChevronDownIcon = () => (
  <svg width="10" height="10" viewBox="0 0 10 10" xmlns="http://www.w3.org/2000/svg" style={{ width: "12px", height: "12px", flexShrink: 0 }}>
    <path d="M2 3.5L5 6.5L8 3.5" stroke="#848483" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round" fill="none" />
  </svg>
);

/** Plus icon for add asset button */
const PlusIcon = () => (
  <svg width="12" height="12" viewBox="0 0 12 12" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
    <path d="M6 2V10M2 6H10" stroke="#006BF4" strokeWidth="1.5" strokeLinecap="round" />
  </svg>
);

/** Reusable percentage quick-select buttons row with transition wrapper */
function PercentButtons({
  visible,
  onSelect,
  maxLabel = "MAX",
}: {
  visible: boolean;
  onSelect: (pct: number) => void;
  maxLabel?: string;
}) {
  const [mounted, setMounted] = useState(false);
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (visible) {
      setMounted(true);
      // Trigger the animation on next frame
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setShow(true));
      });
    } else {
      setShow(false);
      const timer = setTimeout(() => setMounted(false), 200);
      return () => clearTimeout(timer);
    }
  }, [visible]);

  if (!mounted) return null;

  return (
    <div
      style={{
        alignItems: "center",
        boxSizing: "border-box",
        display: "flex",
        gap: "6px",
        width: "100%",
        overflow: "hidden",
        maxHeight: show ? "40px" : "0px",
        opacity: show ? 1 : 0,
        marginTop: show ? "0px" : "-4px",
        transition: "max-height 0.2s ease-out, opacity 0.2s ease-out, margin-top 0.15s ease-out",
      }}
    >
      {[25, 50, 75].map((pct) => (
        <button
          key={pct}
          onClick={() => onSelect(pct)}
          style={{
            alignItems: "center",
            backgroundColor: "#F4F4F3",
            borderRadius: "8px",
            boxSizing: "border-box",
            display: "flex",
            flex: "1 1 0%",
            justifyContent: "center",
            paddingBlock: "5px",
            paddingInline: "10px",
            border: "none",
            cursor: "pointer",
          }}
        >
          <div
            style={{
              boxSizing: "border-box",
              color: "#363635",
              fontFamily: '"Geist", system-ui, sans-serif',
              fontSize: "12px",
              fontWeight: 500,
              lineHeight: "20px",
            }}
          >
            {pct}%
          </div>
        </button>
      ))}
      <button
        onClick={() => onSelect(100)}
        style={{
          alignItems: "center",
          backgroundColor: "#E8F0FF",
          borderRadius: "8px",
          boxSizing: "border-box",
          display: "flex",
          flex: "1 1 0%",
          justifyContent: "center",
          paddingBlock: "5px",
          paddingInline: "10px",
          border: "none",
          cursor: "pointer",
        }}
      >
        <div
          style={{
            boxSizing: "border-box",
            color: "#006BF4",
            fontFamily: '"Geist", system-ui, sans-serif',
            fontSize: "12px",
            fontWeight: 500,
            letterSpacing: "0.02em",
            lineHeight: "20px",
          }}
        >
          {maxLabel}
        </div>
      </button>
    </div>
  );
}

/** Add asset button with smooth transition */
function AddAssetButton({
  visible,
  label,
  onClick,
}: {
  visible: boolean;
  label: string;
  onClick: () => void;
}) {
  const [mounted, setMounted] = useState(false);
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (visible) {
      setMounted(true);
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setShow(true));
      });
    } else {
      setShow(false);
      const timer = setTimeout(() => setMounted(false), 200);
      return () => clearTimeout(timer);
    }
  }, [visible]);

  if (!mounted) return null;

  return (
    <div
      style={{
        overflow: "hidden",
        maxHeight: show ? "50px" : "0px",
        opacity: show ? 1 : 0,
        transition: "max-height 0.2s ease-out, opacity 0.2s ease-out",
      }}
    >
      <button
        onClick={onClick}
        style={{
          alignItems: "center",
          alignSelf: "stretch",
          backgroundColor: "#F4F7FE",
          borderRadius: "8px",
          boxSizing: "border-box",
          display: "flex",
          gap: "6px",
          justifyContent: "center",
          paddingBlock: "9px",
          paddingInline: "9px",
          border: "none",
          cursor: "pointer",
          width: "100%",
        }}
      >
        <PlusIcon />
        <div
          style={{
            boxSizing: "border-box",
            color: "#006BF4",
            fontFamily: '"Geist", system-ui, sans-serif',
            fontSize: "12px",
            fontWeight: 500,
            lineHeight: "20px",
          }}
        >
          {label}
        </div>
      </button>
    </div>
  );
}

export function SwapIdleForm({
  amount,
  onAmountChange,
  fromTokens,
  toToken,
  totalBalance,
  receiveBalance,
  usdValue,
  onOpenSourcePicker,
  onOpenDestPicker,
  onOpenRecipientPicker,
  recipientAddress,
  swapType,
}: SwapIdleFormProps) {
  const [hoveredPanel, setHoveredPanel] = useState<"send" | "receive" | null>(null);

  const sanitizeInput = (raw: string): string => {
    let next = raw.replaceAll(/[^0-9.]/g, "");
    const parts = next.split(".");
    if (parts.length > 2) next = parts[0] + "." + parts.slice(1).join("");
    if (next === ".") next = "0.";
    return next;
  };

  const handleSendInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    onAmountChange(sanitizeInput(e.target.value), "send");
  };

  const handleReceiveInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    onAmountChange(sanitizeInput(e.target.value), "receive");
  };

  const isExactIn = swapType === "exactIn";

  const handleSendPercent = (pct: number) => {
    if (!totalBalance) return;
    const bal = parseFloat(totalBalance.replace(/[^0-9.]/g, ""));
    if (isNaN(bal)) return;
    const val = bal * (pct / 100);
    onAmountChange(val.toFixed(6).replace(/\.?0+$/, ""), "send");
  };

  const handleReceivePercent = (pct: number) => {
    if (!receiveBalance) return;
    const bal = parseFloat(receiveBalance.replace(/[^0-9.]/g, ""));
    if (isNaN(bal)) return;
    const val = bal * (pct / 100);
    onAmountChange(val.toFixed(6).replace(/\.?0+$/, ""), "receive");
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "16px", width: "100%" }}>

      {/* ─── SEND PANEL ─── */}
      <div
        onMouseEnter={() => setHoveredPanel("send")}
        onMouseLeave={() => setHoveredPanel(null)}
        style={{
          alignItems: "center",
          backgroundColor: "#FFFFFE",
          borderColor: "#E8E8E7",
          borderRadius: "12px",
          borderStyle: "solid",
          borderWidth: "1px",
          boxShadow: "#1616150A 0px 1px 2px",
          boxSizing: "border-box",
          display: "flex",
          flexDirection: "column",
          fontVariantNumeric: "tabular-nums",
          gap: "12px",
          justifyContent: "center",
          paddingBlock: "16px",
          paddingInline: "16px",
          width: "100%",
        }}
      >
        {/* Header row: SEND + Total Balance */}
        <div style={{ alignItems: "center", alignSelf: "stretch", boxSizing: "border-box", display: "flex", justifyContent: "space-between", width: "100%" }}>
          <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, letterSpacing: "0.08em", lineHeight: "20px", textTransform: "uppercase" as const }}>
            Send
          </div>
          <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "4px" }}>
            <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
              Total Balance:
            </div>
            <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
              ${totalBalance}
            </div>
          </div>
        </div>

        {/* Amount + Asset pill row */}
        <div style={{ alignSelf: "stretch", boxSizing: "border-box", display: "flex", flexDirection: "column", gap: "8px", width: "100%" }}>
          <div style={{ alignItems: "center", alignSelf: "stretch", boxSizing: "border-box", display: "flex", gap: "10px", justifyContent: "space-between", width: "100%" }}>
            <input
              type="text"
              placeholder="0"
              value={isExactIn ? amount : ""}
              onChange={handleSendInput}
              style={{
                boxSizing: "border-box",
                color: (isExactIn && amount) ? "#161615" : "#9E9E9C",
                fontFamily: '"Delight-Medium", "Delight", system-ui, sans-serif',
                fontSize: "36px",
                fontWeight: 500,
                lineHeight: "44px",
                background: "transparent",
                border: "none",
                outline: "none",
                padding: 0,
                width: "100%",
                minWidth: 0,
              }}
            />

            {/* Asset selector pill */}
            <button
              onClick={onOpenSourcePicker}
              style={{
                alignItems: "center",
                backgroundColor: "#FFFFFE",
                borderColor: fromTokens.length > 0 ? "#E8E8E7" : "#C8C8C7",
                borderRadius: "999px",
                borderStyle: fromTokens.length > 0 ? "solid" : "dashed",
                borderWidth: "1px",
                boxShadow: fromTokens.length > 0 ? "#1616150A 0px 1px 2px" : "none",
                boxSizing: "border-box",
                display: "flex",
                gap: "8px",
                paddingBottom: "5px",
                paddingLeft: fromTokens.length > 0 ? "4px" : "8px",
                paddingRight: "10px",
                paddingTop: "5px",
                cursor: "pointer",
                flexShrink: 0,
              }}
            >
              {fromTokens.length > 0 ? (
                fromTokens.length === 1 ? (
                  <div style={{ boxSizing: "border-box", flexShrink: 0, height: "26px", position: "relative" as const, width: "26px" }}>
                    <img src={fromTokens[0].logo} alt={fromTokens[0].symbol} style={{ borderRadius: "999px", height: "26px", width: "26px", objectFit: "cover" as const }} />
                    {fromTokens[0].chainLogo && (
                      <img src={fromTokens[0].chainLogo} alt={fromTokens[0].chainName} style={{ borderRadius: "999px", bottom: -2, height: "12px", outline: "1px solid #FFFFFE", position: "absolute" as const, right: -2, width: "12px", objectFit: "cover" as const }} />
                    )}
                  </div>
                ) : (
                  <div style={{ width: "26px", height: "26px", borderRadius: "999px", backgroundColor: "#E8F0FF", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "10px", fontWeight: 700, color: "#006BF4", flexShrink: 0 }}>
                    +{fromTokens.length}
                  </div>
                )
              ) : (
                <div style={{ borderColor: "#C8C8C7", borderRadius: "999px", borderStyle: "dashed", borderWidth: "1.5px", boxSizing: "border-box", flexShrink: 0, height: "22px", width: "22px" }} />
              )}
              <div style={{ boxSizing: "border-box", color: "#161615", fontFamily: '"Geist", system-ui, sans-serif', fontSize: fromTokens.length > 0 ? "14px" : "16px", fontWeight: 500, lineHeight: fromTokens.length > 0 ? "18px" : "24px" }}>
                {fromTokens.length > 0 ? (fromTokens.length === 1 ? fromTokens[0].symbol : "Sources") : "Assets"}
              </div>
              <ChevronDownIcon />
            </button>
          </div>

          {/* USD value + balance row */}
          <div style={{ alignItems: "center", alignSelf: "stretch", boxSizing: "border-box", display: "flex", justifyContent: "space-between", width: "100%" }}>
            <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
              ≈ ${usdValue || "0.00"}
            </div>
            {fromTokens.length > 0 && fromTokens.length === 1 && (
              <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "5px" }}>
                <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", fontVariantNumeric: "tabular-nums", lineHeight: "20px" }}>
                  Balance:
                </div>
                <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", fontVariantNumeric: "tabular-nums", lineHeight: "20px" }}>
                  {fromTokens[0].balance}
                </div>
              </div>
            )}
          </div>

          {/* 25% 50% 75% MAX — hover transition */}
          <PercentButtons
            visible={hoveredPanel === "send"}
            onSelect={handleSendPercent}
          />
        </div>

        {/* Add asset button — only after first source selected */}
        <AddAssetButton
          visible={fromTokens.length > 0}
          label={fromTokens.length > 1 ? `${fromTokens.length} sources selected` : "Add asset"}
          onClick={onOpenSourcePicker}
        />
      </div>

      {/* ─── RECEIVE PANEL ─── */}
      <div
        onMouseEnter={() => setHoveredPanel("receive")}
        onMouseLeave={() => setHoveredPanel(null)}
        style={{
          backgroundColor: "#FFFFFE",
          borderColor: "#E8E8E7",
          borderRadius: "12px",
          borderStyle: "solid",
          borderWidth: "1px",
          boxShadow: "#1616150A 0px 1px 2px",
          boxSizing: "border-box",
          display: "flex",
          flexDirection: "column",
          fontVariantNumeric: "tabular-nums",
          gap: "12px",
          paddingBlock: "20px",
          paddingInline: "16px",
          width: "100%",
        }}
      >
        <div style={{ alignSelf: "stretch", boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, letterSpacing: "0.08em", lineHeight: "20px", textTransform: "uppercase" as const, width: "100%" }}>
          Receive
        </div>

        <div style={{ alignSelf: "stretch", boxSizing: "border-box", display: "flex", flexDirection: "column", gap: "4px", width: "100%" }}>
          <div style={{ alignItems: "center", alignSelf: "stretch", boxSizing: "border-box", display: "flex", gap: "10px", justifyContent: "space-between", width: "100%" }}>
            <input
              type="text"
              placeholder="0"
              value={!isExactIn ? amount : ""}
              onChange={handleReceiveInput}
              style={{
                boxSizing: "border-box",
                color: (!isExactIn && amount) ? "#161615" : "#9E9E9C",
                fontFamily: '"Delight-Medium", "Delight", system-ui, sans-serif',
                fontSize: "36px",
                fontWeight: 500,
                lineHeight: "44px",
                background: "transparent",
                border: "none",
                outline: "none",
                padding: 0,
                width: "100%",
                minWidth: 0,
              }}
            />

            {/* Destination asset pill */}
            <button
              onClick={onOpenDestPicker}
              style={{
                alignItems: "center",
                backgroundColor: "#FFFFFE",
                borderColor: toToken ? "#E8E8E7" : "#C8C8C7",
                borderRadius: "999px",
                borderStyle: toToken ? "solid" : "dashed",
                borderWidth: "1px",
                boxShadow: toToken ? "#1616150A 0px 1px 2px" : "none",
                boxSizing: "border-box",
                display: "flex",
                gap: "8px",
                paddingBottom: "5px",
                paddingLeft: toToken ? "5px" : "8px",
                paddingRight: "10px",
                paddingTop: "5px",
                cursor: "pointer",
                flexShrink: 0,
              }}
            >
              {toToken ? (
                <div style={{ boxSizing: "border-box", flexShrink: 0, height: "26px", position: "relative" as const, width: "26px" }}>
                  <img src={toToken.logo} alt={toToken.symbol} style={{ borderRadius: "999px", height: "26px", width: "26px", objectFit: "cover" as const }} />
                  {toToken.chainLogo && (
                    <img src={toToken.chainLogo} alt={toToken.chainName} style={{ borderRadius: "999px", bottom: -2, height: "12px", outline: "1px solid #FFFFFE", position: "absolute" as const, right: -2, width: "12px", objectFit: "cover" as const }} />
                  )}
                </div>
              ) : (
                <div style={{ borderColor: "#C8C8C7", borderRadius: "999px", borderStyle: "dashed", borderWidth: "1.5px", boxSizing: "border-box", flexShrink: 0, height: "22px", width: "22px" }} />
              )}
              <div style={{ boxSizing: "border-box", color: "#161615", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "16px", fontWeight: 500, lineHeight: "24px" }}>
                {toToken ? toToken.symbol : "Assets"}
              </div>
              <ChevronDownIcon />
            </button>
          </div>

          {/* USD value + balance row */}
          <div style={{ alignItems: "center", alignSelf: "stretch", boxSizing: "border-box", display: "flex", justifyContent: "space-between", width: "100%" }}>
            <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
              ≈ $0.00
            </div>
            {toToken && toToken.balance && (
              <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "5px" }}>
                <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", fontVariantNumeric: "tabular-nums", lineHeight: "20px" }}>
                  Balance:
                </div>
                <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", fontVariantNumeric: "tabular-nums", lineHeight: "20px" }}>
                  {toToken.balance}
                </div>
              </div>
            )}
          </div>

          {/* 25% 50% 75% MAX — hover transition (receive side) */}
          <PercentButtons
            visible={hoveredPanel === "receive"}
            onSelect={handleReceivePercent}
          />
        </div>

        {/* Recipient section — only shown when handler exists */}
        {onOpenRecipientPicker && (
          <>
            <div style={{ alignSelf: "stretch", backgroundColor: "#E8E8E7", boxSizing: "border-box", flexShrink: 0, height: "1px", marginTop: "4px", width: "100%" }} />
            <div style={{ alignSelf: "stretch", boxSizing: "border-box", display: "flex", flexDirection: "column", gap: "6px", paddingTop: "2px", width: "100%" }}>
              <div style={{ boxSizing: "border-box", color: "#7C7C7A", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, letterSpacing: "0.08em", lineHeight: "20px", textTransform: "uppercase" as const }}>
                Recipient
              </div>
              <div style={{ alignItems: "center", alignSelf: "stretch", boxSizing: "border-box", display: "flex", gap: "10px", justifyContent: "space-between", width: "100%" }}>
                <div style={{ boxSizing: "border-box", color: "#006BF4", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "16px", fontVariantNumeric: "tabular-nums", fontWeight: 500, lineHeight: "18px" }}>
                  {recipientAddress ? `${recipientAddress.slice(0, 6)}…${recipientAddress.slice(-4)}` : "Select recipient"}
                </div>
                <button
                  onClick={onOpenRecipientPicker}
                  style={{ alignItems: "center", backgroundColor: "#F4F6FF", borderRadius: "4px", boxSizing: "border-box", display: "flex", gap: "4px", paddingBlock: "8px", paddingInline: "12px", border: "none", cursor: "pointer" }}
                >
                  <div style={{ boxSizing: "border-box", color: "#006BF4", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, lineHeight: "13px" }}>
                    Edit
                  </div>
                </button>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

"use client";
import { nexusOneTheme } from "../theme";
import React, { useState } from "react";
import {
  ArrowRight,
  Clock,
  Loader2,
  ChevronDown,
  ChevronUp,
  Layers,
  TrendingDown,
  Wallet,
  Send,
} from "lucide-react";
import { Button } from "../../ui/button";
import { type NexusOneMode, type DepositOpportunity } from "../types";
import { type SwapTokenOption } from "./swap-asset-selector";

// ---------------------------------------------------------------------------
// Types for intent data from SDK swap intent hook
// ---------------------------------------------------------------------------
export interface SwapIntentSource {
  amount: string;
  chain: { id: number; logo: string; name: string };
  token: { contractAddress: string; decimals: number; symbol: string };
}

export interface SwapIntentDestination {
  amount: string;
  chain: { id: number; logo: string; name: string };
  token: { contractAddress: string; decimals: number; symbol: string };
  gas: {
    amount: string;
    token: { contractAddress: string; decimals: number; symbol: string };
  };
}

export interface SwapIntentData {
  sources: SwapIntentSource[];
  destination: SwapIntentDestination;
}

export interface SwapIntentPreviewProps {
  /** The from tokens selected by user (for logo display) */
  fromTokens?: SwapTokenOption[];
  fromToken?: SwapTokenOption;
  toToken?: SwapTokenOption;
  /** Human-readable amount user entered */
  fromAmount: string;
  /** Total USD value of what user is swapping */
  fromAmountUsd?: string;
  /** Amount user will receive */
  toAmount?: string;
  toAmountUsd?: string;
  toAmountTokens?: string;
  totalFeeUsd?: string;
  estimatedTime?: string;
  isLoading?: boolean;
  /** Actual SDK intent data from setOnSwapIntentHook */
  intentData?: SwapIntentData | null;
  mode?: NexusOneMode;
  opportunity?: DepositOpportunity;
  /** Pass the full user swap balances to reliably map token logos for exactOut */
  swapBalances?: any[] | null;
  /** Global asset dictionary mapped across all topologies, guaranteeing data even when balances===0 */
  supportedTokenAssets?: any[] | null;
  activeMode?: NexusOneMode;
  onAccept: () => void;
  onReject: () => void;
}

export function SwapIntentPreview({
  fromTokens,
  fromToken,
  toToken,
  fromAmount,
  fromAmountUsd,
  toAmount,
  toAmountUsd,
  toAmountTokens,
  totalFeeUsd,
  estimatedTime = "~10s",
  isLoading,
  intentData,
  swapBalances,
  supportedTokenAssets,
  activeMode,
  mode,
  opportunity,
  onAccept,
  onReject,
}: SwapIntentPreviewProps) {
  const [showDetails, setShowDetails] = useState(false);

  const intentSources = intentData?.sources ?? [];
  const intentDest = intentData?.destination;

  const getTokenLogo = (chainId: number, contractAddress?: string, symbol?: string) => {
    // 1. Immediately prioritize dynamic balances (since they guarantee verified holding context)
    if (swapBalances && Array.isArray(swapBalances)) {
      for (const asset of swapBalances) {
        if (!asset.breakdown || !Array.isArray(asset.breakdown)) continue;
        for (const bd of asset.breakdown) {
          const matchChain = bd.chain?.id === chainId;
          const matchAddress = contractAddress && bd.contractAddress
            ? bd.contractAddress.toLowerCase() === contractAddress.toLowerCase()
            : false;
          const matchSymbol = bd.symbol === symbol || asset.symbol === symbol;

          if (matchChain && (matchAddress || matchSymbol)) {
            if (asset.icon) return asset.icon;
          }
        }
      }
    }

    // 2. Fall back to the absolute registry for tokens the user lacks balances for (e.g. MATIC destination limits)
    if (supportedTokenAssets && Array.isArray(supportedTokenAssets)) {
      const chain = supportedTokenAssets.find((c: any) => c.id === chainId);
      if (chain && Array.isArray(chain.tokens)) {
        const token = chain.tokens.find((t: any) => {
          if (contractAddress && t.contractAddress) {
             return t.contractAddress.toLowerCase() === contractAddress.toLowerCase();
          }
          return t.symbol === symbol;
        });
        if (token?.logo) return token.logo;
      }
    }

    return undefined;
  };

  // Resolve display sources — prefer intent data if available
  const sources =
    intentSources.length > 0
      ? intentSources.map((s) => ({
          symbol: s.token.symbol,
          contractAddress: s.token.contractAddress,
          chainId: s.chain.id,
          logo: getTokenLogo(s.chain.id, s.token.contractAddress, s.token.symbol),
          name: s.token.symbol,
          chainName: s.chain.name,
          chainLogo: s.chain.logo,
          decimals: s.token.decimals,
        }))
      : fromTokens && fromTokens.length > 0
        ? fromTokens
        : fromToken
          ? [fromToken]
          : [];

  // Compute actual USD values from intent if available
  const displayFromAmountUsd = intentSources.length > 0
    ? intentSources.reduce((sum, s) => sum + Number((s as any).value || s.amount || 0), 0).toFixed(2)
    : (fromAmountUsd || fromAmount);

  const displayToAmountUsd = intentDest
    ? Number((intentDest as any).value || intentDest.amount || 0).toFixed(2)
    : (toAmountUsd || toAmount || "—");

  const displayToAmountTokens = intentDest
    ? `${Number(intentDest.amount || 0).toFixed(4)}`
    : toAmountTokens;

  const displayFeeUsd = (() => {
    if (intentSources.length > 0 && intentDest) {
      const totalIn = intentSources.reduce((sum, s) => sum + Number((s as any).value || s.amount || 0), 0);
      const totalOut = Number((intentDest as any).value || intentDest.amount || 0);
      const fee = totalIn - totalOut;
      return fee > 0 ? fee.toFixed(2) : "0.00";
    }
    return totalFeeUsd || "0.00";
  })();

  // Build summary label like "USDC, ETH +2 more"
  const sourceLabel = (() => {
    if (intentSources.length > 0) {
      const syms = [...new Set(intentSources.map((s) => s.token.symbol))];
      if (syms.length <= 2) return syms.join(", ");
      return `${syms[0]}, ${syms[1]} +${syms.length - 2} more`;
    }
    if (sources.length === 0) return "—";
    const syms = [...new Set(sources.map((s) => s.symbol))];
    if (syms.length <= 2) return syms.join(", ");
    return `${syms[0]}, ${syms[1]} +${syms.length - 2} more`;
  })();

  // Enable details breakdown even if there is exactly 1 source as requested by user
  const hasBreakdown = intentSources.length > 0 || sources.length > 0;
  const destTokenSymbol = intentDest?.token.symbol || toToken?.symbol || "—";

  return (
    <div className="flex flex-col gap-y-4 w-full">
      {/* ------------------------------------------------------------------ */}
      {/* White card: wraps logos + detail rows                              */}
      {/* ------------------------------------------------------------------ */}
      <div
        style={{
          background: "var(--background-secondary, #FFFFFF)",
          borderRadius: "12px",
          border: "1px solid var(--border-default, var(--border-default, #E8E8E7))",
          boxShadow: "0px 1px 12px 0px #5B5B5B0D",
          padding: "16px",
        }}
      >
        {/* Token logo visualization + estimated time */}
        <div className="flex flex-col items-center gap-y-2 pb-3">
        <div className="flex items-center gap-x-3">
          {/* Source token logos (tightly stacked, no white border) */}
          <div className="flex items-center">
            {sources.slice(0, 3).map((token, i) => {
              const matchingIntentSrc = intentSources.find(
                 is => (is.token.contractAddress || "").toLowerCase() === (token.contractAddress || "").toLowerCase()
                    && is.chain.id === token.chainId
              );
              let amountStr = "—";
              if (matchingIntentSrc) {
                amountStr = `${Number(matchingIntentSrc.amount || 0).toFixed(4)} ${token.symbol}`;
              } else if (sources.length > 0) {
                const evenlySplitAmt = Number(fromAmount) / sources.length;
                amountStr = `${evenlySplitAmt.toFixed(4)} ${token.symbol}`;
              }

              return (
              <div
                key={`src-${token.contractAddress}-${token.chainId}-${i}`}
                className="relative shrink-0 group/logo cursor-default"
                style={{ marginLeft: i > 0 ? "-12px" : "0", zIndex: 3 - i }}
              >
                {/* When hovered, we force this relative block to bump above its siblings */}
                <div className="group-hover/logo:z-20 relative">
                  {token.logo ? (
                    <img
                      src={token.logo}
                      alt={token.symbol}
                      className="rounded-full object-cover transition-transform group-hover/logo:scale-105"
                      style={{ width: 36, height: 36 }}
                      onError={(e) => {
                        (e.target as HTMLImageElement).style.display = "none";
                      }}
                    />
                  ) : (
                    <div
                      className="rounded-full flex items-center justify-center text-xs font-bold text-white transition-transform group-hover/logo:scale-105"
                      style={{
                        width: 36,
                        height: 36,
                        background:
                          "var(--interactive-button-primary-background, var(--foreground-brand, #006BF4))",
                      }}
                    >
                      {token.symbol.slice(0, 2)}
                    </div>
                  )}

                  {/* Tooltip */}
                  <div
                    className="absolute left-1/2 -translate-x-1/2 top-full mt-2 opacity-0 group-hover/logo:opacity-100 transition-opacity whitespace-nowrap pointer-events-none flex items-center justify-center z-50 text-center"
                    style={{
                      background: "var(--background-inverse, var(--foreground-primary, #161615))",
                      boxShadow: "0px 1px 4px 0px #5555550D",
                      minWidth: 94,
                      height: 30,
                      borderRadius: 4,
                      gap: 8,
                      padding: "6px 10px",
                      fontFamily: "Geist, var(--font-geist-sans), sans-serif",
                      fontWeight: 400,
                      fontSize: 14,
                      lineHeight: "18px",
                      color: "var(--foreground-inverse, #F0F0EF)",
                    }}
                  >
                    {amountStr}
                  </div>
                </div>
              </div>
            )})}
          </div>

          {/* Arrow */}
          <ArrowRight
            style={{
              width: 24,
              height: 24,
              color: "var(--foreground-muted, var(--foreground-muted, #848483))",
            }}
          />

          {/* Destination token logo */}
          {toToken && (
            <div className="relative shrink-0 group/logo cursor-default z-0 hover:z-20">
              {toToken.logo ? (
                <img
                  src={toToken.logo}
                  alt={toToken.symbol}
                  className="rounded-full object-cover transition-transform group-hover/logo:scale-105"
                  style={{ width: 36, height: 36 }}
                  onError={(e) => {
                    (e.target as HTMLImageElement).style.display = "none";
                  }}
                />
              ) : (
                <div
                  className="rounded-full flex items-center justify-center text-xs font-bold text-white transition-transform group-hover/logo:scale-105"
                  style={{
                    width: 36,
                    height: 36,
                    background:
                      "var(--interactive-button-primary-background, var(--foreground-brand, #006BF4))",
                  }}
                >
                  {toToken.symbol.slice(0, 2)}
                </div>
              )}
              {mode === "deposit" && opportunity?.logo && (
                <img
                   src={opportunity.logo}
                   alt="Protocol Overlay"
                   className="absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white object-cover bg-white pointer-events-none"
                />
              )}

              {/* Tooltip */}
              <div
                className="absolute left-1/2 -translate-x-1/2 top-full mt-2 opacity-0 group-hover/logo:opacity-100 transition-opacity whitespace-nowrap pointer-events-none flex items-center justify-center z-50 text-center"
                style={{
                  background: "var(--background-inverse, var(--foreground-primary, #161615))",
                  boxShadow: "0px 1px 4px 0px #5555550D",
                  minWidth: 94,
                  height: 30,
                  borderRadius: 4,
                  gap: 8,
                  padding: "6px 10px",
                  fontFamily: "Geist, var(--font-geist-sans), sans-serif",
                  fontWeight: 400,
                  fontSize: 14,
                  lineHeight: "18px",
                  color: "var(--foreground-inverse, #F0F0EF)",
                }}
              >
                {mode === "deposit" ? (
                  displayToAmountTokens && displayToAmountTokens !== "—"
                    ? `${displayToAmountTokens} ${destTokenSymbol} on ${opportunity?.title || opportunity?.protocol || "Opportunity"}`
                    : `— ${destTokenSymbol} on ${opportunity?.title || opportunity?.protocol || "Opportunity"}`
                ) : (
                  displayToAmountTokens && displayToAmountTokens !== "—"
                    ? `${displayToAmountTokens} ${destTokenSymbol}`
                    : `— ${destTokenSymbol}`
                )}
              </div>
            </div>
          )}
        </div>

        {/* Estimated time */}
        <div className="flex items-center gap-x-1">
          <span
            style={{
              fontFamily: "Geist, var(--font-geist-sans), sans-serif",
              fontWeight: 400,
              fontSize: "13px",
              lineHeight: "18px",
              color: "var(--widget-card-foreground-muted, var(--foreground-muted, #848483))",
            }}
          >
            in about {estimatedTime}
          </span>
          <Clock
            style={{
              width: 16,
              height: 16,
              color: "var(--widget-card-foreground-muted, var(--foreground-muted, #848483))",
            }}
          />
        </div>
        </div>

        {/* -------------------------------------------------------------- */}
        {/* Detail rows                                                    */}
        {/* -------------------------------------------------------------- */}
        <div className="flex flex-col gap-y-0">
        {/* You Swap / Send */}
        <div className="flex items-start justify-between px-1 py-3">
          <div className="flex items-start gap-x-2.5">
            {mode === "deposit" ? (
              <svg
                className="shrink-0 mt-0.5"
                style={{ width: 20, height: 20, color: "var(--foreground-muted, var(--foreground-muted, #848483))" }}
                viewBox="0 0 20 20"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
              >
                <path d="M16.25 3.75H3.75C3.25272 3.75 2.77581 3.94754 2.42417 4.29917C2.07254 4.65081 1.875 5.12772 1.875 5.625V14.375C1.875 14.8723 2.07254 15.3492 2.42417 15.7008C2.77581 16.0525 3.25272 16.25 3.75 16.25H16.25C16.7473 16.25 17.2242 16.0525 17.5758 15.7008C17.9275 15.3492 18.125 14.8723 18.125 14.375V5.625C18.125 5.12772 17.9275 4.65081 17.5758 4.29917C17.2242 3.94754 16.7473 3.75 16.25 3.75ZM3.125 7.5H16.875V8.75H12.5C12.3342 8.75 12.1753 8.81585 12.0581 8.93306C11.9408 9.05027 11.875 9.20924 11.875 9.375C11.875 9.87228 11.6775 10.3492 11.3258 10.7008C10.9742 11.0525 10.4973 11.25 10 11.25C9.50272 11.25 9.02581 11.0525 8.67417 10.7008C8.32254 10.3492 8.125 9.87228 8.125 9.375C8.125 9.20924 8.05915 9.05027 7.94194 8.93306C7.82473 8.81585 7.66576 8.75 7.5 8.75H3.125V7.5ZM3.75 5H16.25C16.4158 5 16.5747 5.06585 16.6919 5.18306C16.8092 5.30027 16.875 5.45924 16.875 5.625V6.25H3.125V5.625C3.125 5.45924 3.19085 5.30027 3.30806 5.18306C3.42527 5.06585 3.58424 5 3.75 5ZM16.25 15H3.75C3.58424 15 3.42527 14.9342 3.30806 14.8169C3.19085 14.6997 3.125 14.5408 3.125 14.375V10H6.9375C7.08095 10.7064 7.46421 11.3415 8.02234 11.7977C8.58047 12.2539 9.27915 12.5031 10 12.5031C10.7208 12.5031 11.4195 12.2539 11.9777 11.7977C12.5358 11.3415 12.9191 10.7064 13.0625 10H16.875V14.375C16.875 14.5408 16.8092 14.6997 16.6919 14.8169C16.5747 14.9342 16.4158 15 16.25 15Z" fill="currentColor"/>
              </svg>
            ) : mode === "send" ? (
              <Send className="shrink-0 mt-0.5" style={{ width: 20, height: 20, color: "var(--foreground-muted, var(--foreground-muted, #848483))" }} />
            ) : (
              <svg
                className="shrink-0 mt-0.5"
                style={{
                  width: 20,
                  height: 20,
                  color: "var(--foreground-muted, var(--foreground-muted, #848483))",
                }}
                viewBox="0 0 20 20"
                fill="none"
                xmlns="http://www.w3.org/2000/svg"
